            const span = document.createElement('span');
            span.textContent = word + ' ';
            container.appendChild(span);
            currentIndex++;

            // Random delay between 0 and 500ms
            const delay = Math.random() * 500;
            setTimeout(showNextWord, delay);
        }
    }

    showNextWord();
});
